55	        previousContracts: 0,
56	      }),
57	    ).toBe(55);
58	  });
59	  it("quote for 3 runes returns premium 65 (60 base block + 5 fee)", () => {
60	    expect(
61	      quote({
62	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
63	        customerYears: 0,
64	        previousContracts: 0,
65	      }),
66	    ).toBe(65);
67	  });
68	  it("quote for 4 runes returns premium 105 (100 base + 5 fee, no block — block requires exactly 3)", () => {
69	    expect(
70	      quote({
71	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
72	        customerYears: 0,
73	        previousContracts: 0,
74	      }),
75	    ).toBe(105);
