77	  it("quote for 7 runes returns premium 180 (175 base + 5 fee)", () => {
78	    expect(
79	      quote({
80	        items: [
81	          { type: "rune" },
82	          { type: "rune" },
83	          { type: "rune" },
84	          { type: "rune" },
85	          { type: "rune" },
86	          { type: "rune" },
87	          { type: "rune" },
88	        ],
89	        customerYears: 0,
90	        previousContracts: 0,
91	      }),
