104	    expect(
105	      quote({
106	        items: [
107	          { type: "rune" },
108	          { type: "rune" },
109	          { type: "rune" },
110	          { type: "moonstone" },
111	          { type: "moonstone" },
112	          { type: "moonstone" },
113	        ],
114	        customerYears: 0,
115	        previousContracts: 0,
116	      }),
117	    ).toBe(125);
118	  });
119	
120	  // --- Item-specific modifiers ---
121	  it("quote for a cursed sword (steel, ench 3) for newcomer (0 yrs, no previous) returns premium 165", () => {
122	    expect(
123	      quote({
124	        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
125	        customerYears: 0,
126	        previousContracts: 0,
127	      }),
128	    ).toBe(165);
129	  });
130	  it("quote for a sword with enchantment exactly 5 applies the high-enchantment surcharge", () => {
131	    expect(
132	      quote({
133	        items: [{ type: "sword", enchantment: 5 }],
134	        customerYears: 0,
135	        previousContracts: 0,
136	      }),
137	    ).toBe(145);
