142	        items: [{ type: "sword", enchantment: 4 }],
143	        customerYears: 0,
144	        previousContracts: 0,
145	      }),
146	    ).toBe(105);
147	  });
148	  it("quote for a cursed sword with enchantment 5 applies both curse and high-enchantment surcharges", () => {
149	    expect(
150	      quote({
151	        items: [{ type: "sword", cursed: true, enchantment: 5 }],
152	        customerYears: 0,
153	        previousContracts: 0,
154	      }),
155	    ).toBe(195);
156	  });
157	
158	  // --- Policy-wide modifiers ---
159	  it.todo("quote for a customer with exactly 2 years applies the 20% loyalty discount");
160	  it.todo("first quote in a scenario applies the 10% first-insurance surcharge");
161	  it.todo("second quote in a scenario applies the 15% follow-up contract discount");
162	
163	  // --- Modifier scope on multi-item policies ---
164	  it.todo("quote for cursed sword + plain amulet: curse surcharge is 50G (50% of cursed item's base, not policy total) → 215G (210 + 5 fee)");
165	
166	  // --- Rounding ---
167	  it.todo("premium calculation yielding 197.5 rounds up to 198 (in MHPCO's favor)");
168	
169	  // --- Integration: long-standing customer's second contract ---
170	  it.todo("quote for cursed sword (steel, ench 7) for 3-yr customer's second quote returns premium 160");
171	
172	  // --- Claim: standard reimbursement ---
173	  it.todo("claim on regular sword (steel, ench 3) with damage 500 → payout 400 (full minus 100 deductible)");
174	  it.todo("claim on a rune (insurance 250, no enchantment/material) with damage 200 → payout 100 (full minus deductible)");
175	
176	  // --- Claim: deductible per damage event ---
177	  it.todo("claim with damage to insured sword (500) and insured amulet (300) → payout 600 (deductible applies once per item)");
178	
179	  // --- Claim: enchantment threshold ---
180	  it.todo("claim on steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
181	
182	  // --- Claim: dragon material ---
183	  it.todo("claim on dragon-material sword ench 5, damage 800 → payout 700 (full reimbursement then deductible)");
184	
185	  // --- Claim: enchantment vs dragon material (50% rule wins) ---
186	  it.todo("claim on dragon-material sword ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
187	  it.todo("claim on dragon-material sword ench 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");
188	
189	  // --- Claim: payout rounding ---
190	  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");
191	
192	  // --- Multiple items of the same type ---
193	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
194	  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");
195	
196	  // --- Cap ---
197	  it.todo("policy covering sword + amulet has insurance sum 1600 and cap 3200");
198	  it.todo("cap is based on unmodified insurance value: cursed sword has cap 2000 regardless of premium modifiers");
199	  it.todo("policy covering sword + 3 runes has insurance sum 1750 (block discount affects premium only, not insurance sum)");
200	
201	  // --- Cap exhaustion across successive claims ---
202	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remaining cap 600");
203	  it.todo("sword (cap 2000): second claim 1500 after first → payout 600, remaining cap 0 (reduced to remaining cap)");
204	
205	  // --- Error cases ---
206	  it.todo("quote with unknown item type causes the CLI to exit with non-zero status and error to stderr");
207	  it.todo("claim referencing a damage entry whose item is not in the policy causes non-zero exit and stderr error");
208	  it.todo("claim with more damage entries of a type than insured (e.g. two sword damages, one sword) causes non-zero exit");
209	  it.todo("claim with a damage entry of negative amount causes non-zero exit and stderr error");
210	});
