3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	
25	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	function groupByType(items: Item[]): Map<string, Item[]> {
35	  const groups = new Map<string, Item[]>();
36	  for (const item of items) {
37	    const group = groups.get(item.type) ?? [];
38	    group.push(item);
39	    groups.set(item.type, group);
40	  }
41	  return groups;
42	}
43	
44	function premiumForGroup(type: string, group: Item[]): number {
45	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
46	    return COMPONENT_BLOCK_PREMIUM;
47	  }
48	  return group.length * BASE_PREMIUM_BY_TYPE[type];
49	}
50	
51	function itemPremium(item: Item): number {
52	  const base = BASE_PREMIUM_BY_TYPE[item.type];
53	  let premium = base;
54	  if (item.cursed) {
55	    premium += base * CURSE_SURCHARGE_RATE;
56	  }
57	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
58	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
59	  }
60	  return premium;
61	}
62	
63	function hasCursedItem(items: Item[]): boolean {
64	  return items.some((item) => item.cursed);
65	}
66	
67	function hasHighEnchantmentItem(items: Item[]): boolean {
68	  return items.some(
69	    (item) => item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
70	  );
71	}
72	
73	function hasItemModifier(items: Item[]): boolean {
74	  return hasCursedItem(items) || hasHighEnchantmentItem(items);
75	}
76	
77	function baseTotalForItems(items: Item[]): number {
78	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
79	}
80	
81	function premiumForItems(items: Item[]): number {
82	  if (hasItemModifier(items)) {
83	    return items.reduce((sum, item) => sum + itemPremium(item), 0);
84	  }
85	  let total = 0;
86	  for (const [type, group] of groupByType(items)) {
87	    total += premiumForGroup(type, group);
88	  }
89	  return total;
90	}
91	
92	function isFirstContract(input: QuoteInput): boolean {
93	  return input.customerYears === 0 && input.previousContracts === 0;
94	}
95	
96	export function quote(input: QuoteInput): number {
97	  let premium = premiumForItems(input.items);
98	  if (hasItemModifier(input.items) && isFirstContract(input)) {
99	    premium += baseTotalForItems(input.items) * FIRST_INSURANCE_SURCHARGE_RATE;
100	  }
101	  return premium + PROCESSING_FEE;
102	}
